Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/ServiceToBeDispensedOnList/ServiceToBeDispensedOn[./Value = " + ServiceToBeDispensedOn.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/ServiceToBeDispensedOnList/ServiceToBeDispensedOn[./Description = " + ServiceToBeDispensedOn.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

